var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부인. 잠시 괜찮으십니까?","JPN":"夫人。よろしいですか？","ENG":"Ma'am. Do you have a moment?","TWN":"夫人，打擾你一下？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 들어오시지요.","JPN":"ええ。どうぞ。","ENG":"Yes, come in.","TWN":"好的，請進吧。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"오셨군요, 에스텔. 버밍엄 백작가에서의 하루는 썩 괜찮으셨는지요?","JPN":"いらっしゃい、エステル。バーミンガム伯爵家での一日はいかがでしたか？","ENG":"Welcome, Esther. I hope your day at House Birmingham was pleasant?","TWN":"喔，你來了，艾斯特。伯明罕伯爵家的一天過得還不錯嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"식사는 분에 넘칠 정도로 과한 대접을 받았습니다.","JPN":"食事は身に余るほどもてなしていただきました。","ENG":"The meal was more than generous, almost too much.","TWN":"這頓飯真是豐盛得超乎想像。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"목욕도… 넓은 탕을 쓰게 해주셔서 감사할 따름이고요.","JPN":"お風呂も……広い浴槽を使わせていただいてとても感謝しています。","ENG":"And... thank you for the use of the spacious bath.","TWN":"洗澡……能用這麼大的浴池，真是感激不盡。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"다만 건네주신 드레스를 입는 건 힘들겠군요.","JPN":"ただ、あのドレスを着るのはちょっと……","ENG":"However, I don't think I can wear the dress you offered.","TWN":"不過，穿上你給的這件禮服恐怕有些困難呢。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 프릴 달린 드레스보다 동물 잠옷이 더 좋았을까요?","JPN":"あら。フリル付きのドレスより、動物のパジャマの方が好みだったかしら？","ENG":"Oh my. Would you prefer animal-themed pajamas to a frilly dress?","TWN":"哎呀，比起蕾絲邊的裙子，動物睡衣更好嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"딸이 생기면 입힐 생각으로 남겨둔 드레스가 마침 경에게 어울린다 싶었는데, 이래서야 옷장 공간만 차지하겠어요.\xA0","JPN":"娘が生まれたら着せようと残しておいたドレスが、ちょうど卿に似合うと思ったのですが。これではクローゼットで場所だけ取ってしまうわ。\xA0","ENG":"I'd been saving that dress for a daughter someday, but it looked so fitting on you that I thought I'd pass it along. Now it's just taking up space in the closet.\xA0","TWN":"本來想著如果有女兒的話就給她穿的裙子，沒想到正好適合你。這樣下去只會佔據衣櫃的空間啊。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"마음은 감사하나, 지금은 이 한 벌로 족합니다.","JPN":"お気遣いはありがたいのですが、今はこれ1着で十分です。","ENG":"I appreciate the sentiment, but I'm content with just this one outfit.","TWN":"心意我領了，不過現在這一套就夠了。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저를 부르신 이유나 말씀해 주시죠, 부인.","JPN":"なぜ私を呼び出したのですか、夫人。","ENG":"Why did you call for me, ma'am?","TWN":"請告訴我你我來何事吧，夫人。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 이미 예상하셨겠지만 내일 원정에 관한 이야기입니다.","JPN":"ふふ。卿も大方予想はついているでしょう。明日の遠征についてです。","ENG":"Haha. As you might've guessed, it's about tomorrow's expedition.","TWN":"呵呵。雖然你可能已經猜到了，但這是關於明天遠征的故事。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"다만, 이쪽은 직접 보는 편이 빠르겠군요.","JPN":"ただ、こちらは直接ご覧になった方が早いでしょうね。","ENG":"Though in this case, it's easier to show you than explain.","TWN":"不過，還是親自看看比較快吧。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"따라오시지요.","JPN":"行きましょう。","ENG":"Come with me.","TWN":"請跟我來吧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"백작가에 전해져 오는 방으로 안내하겠습니다.","JPN":"伯爵家に代々伝わる部屋へとご案内しますわ。","ENG":"I'll take you to a room passed down through House Birmingham.","TWN":"我將帶你前往伯爵家代代相傳的房間。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"여긴 지하임에도 빛이 들어오는 특이한 구조로군요.","JPN":"ここは地下なのに光が差す、独特な構造をしているのですね。","ENG":"Interesting... this chamber's underground, yet it lets in light.","TWN":"這裡雖然是地下，卻有光線照射進來的特殊結構啊。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"분위기를 보면 어떠한 법식을 치르는 곳 같습니다.","JPN":"雰囲気からすると、何か儀礼を行うところのようですが。","ENG":"And by the atmosphere, it looks like a ceremonial space of some kind.","TWN":"從氛圍來看，這裡似乎是舉行某種儀式的地方。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 말씀처럼 이곳은 인도자들의 지혜와 속삭임이 남아있는 장소입니다.","JPN":"ええ。おっしゃるとおり、ここは導き手の知恵とささやきが残されている場所です。","ENG":"Indeed. As you guessed, this is a place where the wisdom and whispers of the Guides linger.","TWN":"是的。正如你所說，這裡是引導者的智慧和低語仍然存在的地方。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그들과 운명으로 얽힌 후계자들은 선조들의 과거를 답습하는 방식으로, 그들의 별빛을 취해왔지요.","JPN":"彼らと運命で結ばれた後継者たちは、先祖の過去をなぞることで星の光を取ってきました。","ENG":"Their successors, bound to them by fate, inherited their starlight by retracing the paths of their ancestors.","TWN":"與他們命運相連的繼承者們通過追隨祖先的過去，汲取了他們的星光。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"인도자라면 기사단의 창립자를 말씀하시는 겁니까?","JPN":"導き手というと、騎士団の創立者のことですか？","ENG":"When you say Guides... do you mean the founders of the Order?","TWN":"引導者是指騎士團的創始人嗎？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 경께서 계신 이 아르카데나 제국이 바로 그녀의 고향입니다.","JPN":"ええ。卿のいる、このアルカデナ帝国こそが彼女の故郷なのです。","ENG":"Yes. The Empire of Arcadena you stand in now was her homeland.","TWN":"是的。你所在的艾爾卡特納帝國正是她的故鄉。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그 증거로… 빛기둥을 향해 손을 뻗어 보시지요.","JPN":"その証拠として……光の柱に向かって手を伸ばしてみてください。","ENG":"As proof... place your hand toward that pillar of light.","TWN":"作為證據……請伸手觸摸光柱吧。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어떠십니까?","JPN":"いかがですか？","ENG":"What do you feel?","TWN":"……怎麼樣？"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"낯설지 않은 감각입니다.","JPN":"知っている感覚です。","ENG":"It's a familiar sensation.","TWN":"這是一種熟悉的感覺。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이건, 마치 버고 소드를 쥔 것 같군요.","JPN":"これは、まるでヴァルゴソードを手に取っているようですね。","ENG":"It feels like holding the Virgo Sword.","TWN":"這感覺就像握住了布林加夫之劍。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무구에 담긴 별빛은 전부 인도자의 힘으로부터 비롯된 것이니, 말씀하신 것이 마냥 다르지는 않습니다.","JPN":"武具に込められた星の光はすべて導き手の力から来たものです。おっしゃることはあながち間違っていません。","ENG":"All starlight embedded in Armaments ultimately comes from the power of the Guide, so it's not a stretch to say that.","TWN":"武器中蘊含的星光全都源自引導者的力量，所以你所說的並不完全不同。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};